using System;
using System.Windows.Forms;

static class Program
{
    [STAThread]
    static void Main()
    {
        ApplicationConfiguration.Initialize();

        // .NET 9 breaking change: ToolStrip/StatusStrip default RenderMode changed
        // from the Professional (gradient) renderer to the System renderer.
        // Restore the .NET 8 visual appearance for all ToolStrip-derived controls.
        ToolStripManager.RenderMode = ToolStripManagerRenderMode.Professional;

        Application.Run(new MainForm());
    }
}

using System;
using System.Windows.Forms;
using System.Windows.Forms.Design;

/// <summary>
/// Wrapper that guards against the .NET 9 breaking change where
/// IWindowsFormsEditorService.DropDownControl now throws
/// ArgumentNullException when passed null instead of silently returning.
/// </summary>
static class SafeEditorService
{
    public static void ShowDropDown(IWindowsFormsEditorService editorService, Control? control)
    {
        if (control is null)
            return;

        editorService.DropDownControl(control);
    }
}

using System;
using System.Runtime.InteropServices;

/// <summary>
/// .NET 9 breaking change: LibraryImport (source-generated P/Invoke) is now
/// the recommended replacement for DllImport. It avoids the runtime stub
/// generation overhead and enables trimming / NativeAOT.
///
/// Before (.NET 8):
///   [DllImport("user32.dll", SetLastError = true)]
///   static extern bool ShowWindow(IntPtr hWnd, int nCmdShow);
///
/// After (.NET 9):
///   [LibraryImport("user32.dll", SetLastError = true)]
///   [return: MarshalAs(UnmanagedType.Bool)]
///   internal static partial bool ShowWindow(IntPtr hWnd, int nCmdShow);
/// </summary>
internal static partial class NativeMethods
{
    [LibraryImport("user32.dll", SetLastError = true)]
    [return: MarshalAs(UnmanagedType.Bool)]
    internal static partial bool ShowWindow(IntPtr hWnd, int nCmdShow);

    [LibraryImport("ole32.dll")]
    internal static partial int CoInitializeEx(IntPtr reserved, uint dwCoInit);

    [LibraryImport("ole32.dll")]
    internal static partial void CoUninitialize();
}

